// Prepare approval request metadata
const input = $input.first().json;

const approvalId = `approval_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
const approverEmail = input.approver_email || process.env.NOTIFICATION_EMAIL_TO || 'team@example.com';
const timeoutHours = input.timeout_hours || 24;
const expiresAt = new Date(Date.now() + timeoutHours * 60 * 60 * 1000).toISOString();

// Build approval and rejection URLs (using n8n's resume URL pattern)
// In production these are generated by the Wait node — this is for the email template
const webhookBase = process.env.WEBHOOK_URL || 'http://localhost:5678';

return [{
  json: {
    ...input,
    approvalId,
    approverEmail,
    timeoutHours,
    expiresAt,
    webhookBase,
    createdAt: new Date().toISOString(),
  }
}];

// Process the approval response
const waitResponse = $input.first().json;
const originalRequest = $('Prepare Approval Request').first().json;

// Check if this was a timeout (no query params) or a webhook response
const isTimeout = !waitResponse?.query?.approve && !waitResponse?.body?.approve;
const isApproved = String(waitResponse?.query?.approve || waitResponse?.body?.approve).toLowerCase() === 'true';

const decision = isTimeout ? 'timeout' : (isApproved ? 'approved' : 'rejected');
const comment = waitResponse?.query?.comment || waitResponse?.body?.comment || '';

return [{
  json: {
    approvalId: originalRequest.approvalId,
    title: originalRequest.title,
    decision,
    decided_at: new Date().toISOString(),
    comment,
    approved: decision === 'approved',
    timeout: decision === 'timeout',
  }
}];
